def gen(rng, size):
    n = rng.randint(1, max(1, min(100, size)))
    oa = (n + 1) // 2
    ea = n // 2

    def fact(x):
        r = 1
        for i in range(2, x + 1):
            r *= i
        return r

    total = 0
    if oa == ea or oa == ea + 1:
        total += fact(oa) * fact(ea)
    if ea == oa or ea == oa + 1:
        total += fact(ea) * fact(oa)
    if total <= 0:
        k = 1
    else:
        cap = min(total, 10 ** 15)
        if rng.random() < 0.15 and cap < 10 ** 15:
            k = min(cap + rng.randint(1, 1000), 10 ** 15)
        else:
            k = rng.randint(1, cap)
    return [n, k]

