from itertools import permutations

class Solution:
    def permute(self, n, k):
        valid = []
        for p in permutations(range(1, n + 1)):
            ok = True
            for i in range(1, len(p)):
                if p[i] % 2 == p[i - 1] % 2:
                    ok = False
                    break
            if ok:
                valid.append(list(p))
        valid.sort()
        if k > len(valid):
            return []
        return valid[k - 1]

