var permute = function(n, k) {
    let K = BigInt(k);
    const fact = [1n];
    for (let i = 1; i <= n; i++) fact.push(fact[i - 1] * BigInt(i));

    function count(oa, ea, parity) {
        if (oa < 0 || ea < 0) return 0n;
        let ok;
        if (parity === 1) ok = (oa === ea) || (oa === ea + 1);
        else ok = (ea === oa) || (ea === oa + 1);
        return ok ? fact[oa] * fact[ea] : 0n;
    }

    let odds = [];
    for (let v = 1; v <= n; v += 2) odds.push(v);
    let evens = [];
    for (let v = 2; v <= n; v += 2) evens.push(v);

    const total = count(odds.length, evens.length, 1) + count(odds.length, evens.length, 0);
    if (K > total) return [];

    const result = [];
    let required = null;
    for (let pos = 0; pos < n; pos++) {
        if (required === null) {
            const candidates = odds.concat(evens).sort((a, b) => a - b);
            let found = false;
            for (const val of candidates) {
                const isOdd = val % 2 === 1;
                const newOa = odds.length - (isOdd ? 1 : 0);
                const newEa = evens.length - (isOdd ? 0 : 1);
                const nextParity = isOdd ? 0 : 1;
                const block = count(newOa, newEa, nextParity);
                if (block > 0n && K <= block) {
                    result.push(val);
                    const pool = isOdd ? odds : evens;
                    pool.splice(pool.indexOf(val), 1);
                    required = nextParity;
                    found = true;
                    break;
                }
                K -= block;
            }
            if (!found) return [];
        } else {
            const pool = required === 1 ? odds : evens;
            const avail = pool.length;
            if (avail === 0) return [];
            const newOa = odds.length - (required === 1 ? 1 : 0);
            const newEa = evens.length - (required === 0 ? 1 : 0);
            const nextParity = required === 1 ? 0 : 1;
            const block = count(newOa, newEa, nextParity);
            const groupTotal = BigInt(avail) * block;
            if (block === 0n || K > groupTotal) return [];
            const idx = Number((K - 1n) / block);
            K = (K - 1n) % block + 1n;
            const val = pool.splice(idx, 1)[0];
            result.push(val);
            required = nextParity;
        }
    }
    return result;
};
